'use client';
import * as React from 'react';
import type { RefObject } from '@mui/x-internals/types';
import type { GridPrivateApiCommon } from '../../models/api/gridApiCommon';
import type { GridPrivateApiCommunity } from '../../models/api/gridApiCommunity';

export const GridPrivateApiContext = React.createContext<unknown>(undefined);

export function useGridPrivateApiContext<
  PrivateApi extends GridPrivateApiCommon = GridPrivateApiCommunity,
>(): RefObject<PrivateApi> {
  const privateApiRef = React.useContext(GridPrivateApiContext);

  if (privateApiRef === undefined) {
    throw new Error(
      'MUI X Data Grid: Could not find the Data Grid private context. ' +
        'This happens when a component is rendered outside of a DataGrid, DataGridPro, or DataGridPremium parent component. ' +
        'Ensure your component is a child of a Data Grid component. ' +
        'This can also happen if you are bundling multiple versions of the Data Grid.',
    );
  }

  return privateApiRef as RefObject<PrivateApi>;
}

import { PinnedColumnPosition } from '../constants';
import type { gridColumnPositionsSelector } from '../../hooks/features/columns';

export const getPinnedCellOffset = (
  pinnedPosition: PinnedColumnPosition | undefined,
  computedWidth: number,
  columnIndex: number,
  columnPositions: ReturnType<typeof gridColumnPositionsSelector>,
  columnsTotalWidth: number,
  scrollbarWidth: number,
) => {
  let pinnedOffset: number | undefined;
  switch (pinnedPosition) {
    case PinnedColumnPosition.LEFT:
      pinnedOffset = columnPositions[columnIndex];
      break;
    case PinnedColumnPosition.RIGHT:
      pinnedOffset =
        columnsTotalWidth - columnPositions[columnIndex] - computedWidth + scrollbarWidth;
      break;
    default:
      pinnedOffset = undefined;
      break;
  }

  // XXX: fix this properly
  if (Number.isNaN(pinnedOffset)) {
    pinnedOffset = undefined;
  }

  return pinnedOffset;
};

import type { accentColors } from '../props/color.prop.js';

type ThemeAccentColor = (typeof accentColors)[number];

export function getMatchingGrayColor(accentColor: ThemeAccentColor) {
  switch (accentColor) {
    case 'tomato':
    case 'red':
    case 'ruby':
    case 'crimson':
    case 'pink':
    case 'plum':
    case 'purple':
    case 'violet':
      return 'mauve';
    case 'iris':
    case 'indigo':
    case 'blue':
    case 'sky':
    case 'cyan':
      return 'slate';
    case 'teal':
    case 'jade':
    case 'mint':
    case 'green':
      return 'sage';
    case 'grass':
    case 'lime':
      return 'olive';
    case 'yellow':
    case 'amber':
    case 'orange':
    case 'brown':
    case 'gold':
    case 'bronze':
      return 'sand';
    case 'gray':
      return 'gray';
  }
}

